sql:
SELECT AVG(t.border_length) AS average_border_length
FROM territories t
WHERE t.border_area_ratio = (
    SELECT border_area_ratio FROM territories WHERE territory_name = 'Italy'
) AND t.border_area_ratio > (
    SELECT border_area_ratio FROM territories WHERE territory_name = 'Italy'
) AND t.territory_name != 'Italy';

SELECT t.territory_name, t.border_length, t.surface_area, t.border_area_ratio
FROM territories t
WHERE t.border_area_ratio > (
    SELECT MAX(ratio_value) 
    FROM border_area_ratios
);

SELECT t.territory_name
FROM territories t
WHERE (
    SELECT SUM(border_length)
    FROM borders b
    WHERE b.territory_id = t.territory_id
) > (
    SELECT AVG(border_length)
    FROM borders
);

external_knowledge:
- A territory is considered 'European' if it is geographically located within the continent of Europe; 
- 'Land borders' refer to international borders that are not maritime, i.e., they are shared borders between territories that are not separated by water; 
- 'Total surface area' refers to the entire area of a territory, including both land and water; 
- 'Population' refers to the number of people living within a territory.

sql:
SELECT territory_name, border_length
FROM territories
WHERE territory_name = 'Monaco';

SELECT COUNT(*) 
FROM territories 
WHERE border_area_ratio > (SELECT AVG(border_area_ratio) FROM territories);

SELECT t.territory_name, t.population
FROM territories t
WHERE t.population > (SELECT AVG(population) FROM territories);

SELECT t.territory_name
FROM territories t
WHERE t.border_length / t.surface_area > (
  SELECT AVG(border_length / surface_area) 
  FROM territories
);

SELECT SUM(area_value) AS total_surface_area
FROM surface_areas
WHERE territory_id = 1;
